// ═══════════════ THEMES ═══════════════
const THEMES={
  dark:{bg:"#0f0e13",cardBg:"#1a1825",surface:"#231f30",border:"rgba(255,255,255,.08)",text:"#e8e6f0",subtext:"rgba(255,255,255,.5)",boardLight:"#EEEED2",boardDark:"#769656"},
  light:{bg:"#f0efe8",cardBg:"#ffffff",surface:"#ece9e0",border:"rgba(0,0,0,.1)",text:"#1a1825",subtext:"rgba(0,0,0,.5)",boardLight:"#EEEED2",boardDark:"#769656"},
};
const SQ=Math.min(48,Math.floor((typeof window!=="undefined"?window.innerWidth-28:400)/8));

// ═══════════════ BOARD ═══════════════
function Board({board,flipped=false,highlights={},onSquare,lastMoved=null,dotHints=[],theme}){
  const rows=flipped?[7,6,5,4,3,2,1,0]:[0,1,2,3,4,5,6,7];
  const cols=flipped?[7,6,5,4,3,2,1,0]:[0,1,2,3,4,5,6,7];
  const BL=theme.boardLight,BD=theme.boardDark;
  return(
    <div style={{display:"inline-block",borderRadius:4,overflow:"hidden",boxShadow:"0 12px 40px rgba(0,0,0,.6),0 0 0 2px rgba(0,0,0,.4)"}}>
      {rows.map(r=>(
        <div key={r} style={{display:"flex"}}>
          {cols.map(c=>{
            const light=(r+c)%2===0;
            const piece=board[r][c];
            const hl=highlights[`${r},${c}`];
            const isLast=lastMoved&&(r===lastMoved.fr&&c===lastMoved.fc||r===lastMoved.tr&&c===lastMoved.tc);
            const isDot=dotHints.some(([dr,dc])=>dr===r&&dc===c);
            let bg=light?BL:BD;
            if(isLast)bg=light?"#F6F669":"#CDD16E";
            if(hl==="sel")bg=light?"#85C1E9":"#2E86C1";
            if(hl==="hint")bg=light?"#FFE082":"#F39C12";
            if(hl==="wrong")bg="#E74C3C";
            const showRank=flipped?c===7:c===0;
            const showFile=flipped?r===0:r===7;
            return(
              <div key={c} onClick={()=>onSquare?.(r,c)} style={{width:SQ,height:SQ,backgroundColor:bg,position:"relative",display:"flex",alignItems:"center",justifyContent:"center",cursor:onSquare?"pointer":"default",userSelect:"none",flexShrink:0}}>
                {piece&&<div style={{width:"90%",height:"90%"}}><PieceSVG type={piece[1]} color={piece[0]}/></div>}
                {isDot&&!piece&&<div style={{width:"30%",height:"30%",borderRadius:"50%",background:"rgba(0,0,0,0.2)",position:"absolute",pointerEvents:"none"}}/>}
                {isDot&&piece&&<div style={{position:"absolute",inset:0,border:"3px solid rgba(0,0,0,0.2)",pointerEvents:"none"}}/>}
                {showRank&&<span style={{position:"absolute",top:2,left:3,fontSize:9,fontWeight:700,color:light?BD:BL,lineHeight:1,pointerEvents:"none"}}>{r2n(r)}</span>}
                {showFile&&<span style={{position:"absolute",bottom:2,right:3,fontSize:9,fontWeight:700,color:light?BD:BL,lineHeight:1,pointerEvents:"none"}}>{c2f(c)}</span>}
              </div>
            );
          })}
        </div>
      ))}
    </div>
  );
}

// ═══════════════ LEARN MODE ═══════════════
function LearnMode({opening,variation,positions,onComplete,theme}){
  const [step,setStep]=useState(0);
  const total=variation.moves.length;
  const pos=positions[step];
  const lm=step>0?{fr:positions[step].mf?.[0],fc:positions[step].mf?.[1],tr:positions[step].mt?.[0],tc:positions[step].mt?.[1]}:null;
  const curMove=step>0?variation.moves[step-1]:null;
  const pct=Math.round((step/total)*100);
  const pairs=[];
  for(let i=0;i<variation.moves.length;i+=2)pairs.push({n:Math.floor(i/2)+1,w:variation.moves[i],b:variation.moves[i+1],wi:i,bi:i+1});
  const T=theme;
  return(
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:12}}>
      <Board board={pos.board} flipped={opening.playAs==="black"} lastMoved={lm} theme={T}/>
      <div style={{width:"100%",height:4,background:T.surface,borderRadius:2}}>
        <div style={{height:"100%",width:`${pct}%`,background:opening.color,borderRadius:2,transition:"width .3s"}}/>
      </div>
      <div style={{background:T.surface,border:`1px solid ${T.border}`,borderRadius:12,padding:"12px 14px",width:"100%",minHeight:64}}>
        {curMove?(<><div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
          <span style={{fontFamily:"Georgia,serif",fontSize:16,color:opening.color,fontWeight:700}}>{curMove.san}</span>
          <span style={{fontSize:11,color:T.subtext,background:T.cardBg,padding:"2px 7px",borderRadius:8}}>{curMove.color==="w"?"♔ Белые":"♚ Чёрные"}</span>
        </div><div style={{color:T.text,fontSize:13,lineHeight:1.5,opacity:.85}}>{curMove.note}</div></>)
        :(<div style={{color:T.subtext,fontSize:13}}>Нажмите «Вперёд» для начала</div>)}
      </div>
      <div style={{background:T.surface,borderRadius:10,padding:10,width:"100%"}}>
        <div style={{fontSize:10,color:T.subtext,marginBottom:6,textTransform:"uppercase",letterSpacing:".06em"}}>Ходы</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:3,alignItems:"center"}}>
          {pairs.map(p=>(
            <span key={p.n} style={{display:"flex",alignItems:"center",gap:2}}>
              <span style={{color:T.subtext,fontSize:11,minWidth:16}}>{p.n}.</span>
              {[p.w,p.b].filter(Boolean).map((mv2,i)=>{
                const idx=i===0?p.wi:p.bi;const active=step===idx+1;
                return(<button key={i} onClick={()=>{setStep(idx+1);playSound("move");}} style={{padding:"3px 6px",borderRadius:5,border:"none",background:active?opening.color:T.cardBg,color:active?"#fff":T.text,cursor:"pointer",fontSize:12,fontWeight:active?700:400,transition:"all .15s"}}>{mv2.san}</button>);
              })}
            </span>
          ))}
        </div>
      </div>
      <div style={{display:"flex",gap:6,flexWrap:"wrap",justifyContent:"center"}}>
        {[["⏮",()=>setStep(0)],["◀",()=>setStep(s=>Math.max(0,s-1))],["▶",()=>{setStep(s=>Math.min(total,s+1));playSound("move");}],["⏭",()=>setStep(total)]].map(([lbl,fn],i)=>(
          <button key={i} onClick={fn} style={{padding:"8px 14px",borderRadius:8,border:"none",background:T.surface,color:T.text,cursor:"pointer",fontSize:14}}>{lbl}</button>
        ))}
        {step===total&&<button onClick={onComplete} style={{padding:"8px 18px",borderRadius:8,border:"none",background:opening.color,color:"#fff",cursor:"pointer",fontSize:14,fontWeight:700}}>Завершить ✓</button>}
      </div>
    </div>
  );
}

// ═══════════════ PRACTICE MODE ═══════════════
function PracticeMode({opening,variation,positions,onComplete,theme}){
  const [step,setStep]=useState(0);
  const [sel,setSel]=useState(null);
  const [done,setDone]=useState(false);
  const [fb,setFb]=useState(null);
  const [hint,setHint]=useState(false);
  const [auto,setAuto]=useState(false);
  const [lm,setLm]=useState(null);
  const total=variation.moves.length;
  const uc=opening.playAs==="white"?"w":"b";
  const cur=step<total?variation.moves[step]:null;
  const isUser=cur&&cur.color===uc;
  const nxt=step<total?positions[step+1]:null;
  const T=theme;

  useEffect(()=>{
    if(done)return;
    if(step>=total){setDone(true);return;}
    if(cur&&cur.color!==uc){
      setAuto(true);
      const t=setTimeout(()=>{
        const p=positions[step+1];
        setLm({fr:p.mf?.[0],fc:p.mf?.[1],tr:p.mt?.[0],tc:p.mt?.[1]});
        playSound(p.changed.length>2?"capture":"move");
        setStep(s=>s+1);setAuto(false);setFb(null);
      },900);
      return()=>clearTimeout(t);
    }
  },[step,done]);

  const reset=()=>{setStep(0);setSel(null);setDone(false);setFb(null);setHint(false);setAuto(false);setLm(null);};
  const {board}=positions[step];
  const hl={};
  if(hint&&nxt?.mf&&!sel)hl[`${nxt.mf[0]},${nxt.mf[1]}`]="hint";
  if(hint&&nxt?.mt&&sel)hl[`${nxt.mt[0]},${nxt.mt[1]}`]="hint";
  if(sel)hl[`${sel[0]},${sel[1]}`]="sel";
  const dots=(hint&&sel&&nxt?.mt)?[nxt.mt]:[];

  const onSq=(r,c)=>{
    if(!isUser||auto||done)return;
    if(!sel){const p=board[r][c];if(p&&p[0]===uc){setSel([r,c]);setHint(false);setFb(null);}}
    else{
      if(r===sel[0]&&c===sel[1]){setSel(null);return;}
      const p=board[r][c];if(p&&p[0]===uc){setSel([r,c]);return;}
      const fOk=nxt?.mf&&sel[0]===nxt.mf[0]&&sel[1]===nxt.mf[1];
      const tOk=nxt?.mt&&r===nxt.mt[0]&&c===nxt.mt[1];
      if(fOk&&tOk){
        setLm({fr:nxt.mf[0],fc:nxt.mf[1],tr:nxt.mt[0],tc:nxt.mt[1]});
        playSound(nxt.changed.length>2?"capture":"move");
        setStep(s=>s+1);setSel(null);setHint(false);setFb({ok:true,text:cur.note});
      }else{playSound("wrong");setFb({ok:false,text:"Неверный ход — нажми «Подсказка»"});setSel(null);}
    }
  };

  return(
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:12}}>
      <Board board={board} flipped={opening.playAs==="black"} highlights={hl} onSquare={onSq} lastMoved={lm} dotHints={dots} theme={T}/>
      <div style={{background:T.surface,border:`1px solid ${T.border}`,borderRadius:12,padding:"12px 14px",width:"100%",minHeight:64}}>
        {done?(
          <div style={{textAlign:"center"}}>
            <div style={{fontSize:28,marginBottom:6}}>🎉</div>
            <div style={{color:"#27AE60",fontWeight:700,marginBottom:10}}>Отлично! Вариант пройден!</div>
            <div style={{display:"flex",gap:8,justifyContent:"center"}}>
              <button onClick={reset} style={{padding:"8px 16px",borderRadius:8,border:"none",background:T.surface,color:T.text,cursor:"pointer",fontSize:13}}>🔄 Повтор</button>
              <button onClick={onComplete} style={{padding:"8px 16px",borderRadius:8,border:"none",background:opening.color,color:"#fff",cursor:"pointer",fontSize:13,fontWeight:700}}>Далее →</button>
            </div>
          </div>
        ):auto?(
          <div style={{color:T.subtext,fontSize:13}}>⏳ Соперник думает...</div>
        ):isUser?(
          <div>
            <div style={{fontSize:13,color:opening.color,fontWeight:600,marginBottom:4}}>🎯 Ваш ход ({opening.playAs==="white"?"♔ Белые":"♚ Чёрные"})</div>
            {fb?<div style={{fontSize:13,color:fb.ok?"#27AE60":"#E74C3C"}}>{fb.ok?"✅ ":""}{fb.text}</div>
               :sel?<div style={{fontSize:13,color:T.subtext}}>Выберите поле для хода</div>
               :<div style={{fontSize:13,color:T.subtext}}>Кликни на свою фигуру</div>}
          </div>
        ):<div style={{color:T.subtext,fontSize:13}}>Загрузка...</div>}
      </div>
      <div style={{display:"flex",gap:8}}>
        <button onClick={()=>setHint(true)} style={{padding:"9px 16px",borderRadius:9,border:"none",background:"rgba(255,165,0,.2)",color:"#FFA500",cursor:"pointer",fontSize:13,fontWeight:600}}>💡 Подсказка</button>
        <button onClick={reset} style={{padding:"9px 16px",borderRadius:9,border:"none",background:T.surface,color:T.text,cursor:"pointer",fontSize:13}}>🔄 Сначала</button>
      </div>
    </div>
  );
}

// ═══════════════ QUIZ MODE ═══════════════
function QuizMode({opening,variation,onComplete,theme}){
  const [qi,setQi]=useState(0);
  const [chosen,setChosen]=useState(null);
  const [answers,setAnswers]=useState([]);
  const [done,setDone]=useState(false);
  const quiz=variation.quiz;
  const q=quiz[qi];
  const score=answers.filter(Boolean).length;
  const T=theme;
  const choose=idx=>{if(chosen!==null)return;setChosen(idx);setAnswers(a=>[...a,idx===q.ans]);};
  const next=()=>{if(qi<quiz.length-1){setQi(i=>i+1);setChosen(null);}else setDone(true);};
  const restart=()=>{setQi(0);setChosen(null);setAnswers([]);setDone(false);};

  if(done){
    const pct=score/quiz.length;
    return(
      <div style={{textAlign:"center",padding:"20px 0"}}>
        <div style={{fontSize:52,marginBottom:12}}>{pct===1?"🏆":pct>=0.6?"🎓":"📚"}</div>
        <div style={{fontFamily:"Georgia,serif",fontSize:30,fontWeight:700,color:opening.color,marginBottom:4}}>{score}/{quiz.length}</div>
        <div style={{color:T.subtext,fontSize:14,marginBottom:20}}>{pct===1?"Отлично! Вы знаете этот вариант!":pct>=0.6?"Хороший результат! Практикуйтесь.":"Повторите теорию и попробуйте снова."}</div>
        <div style={{display:"flex",gap:8,justifyContent:"center",marginBottom:20}}>
          {answers.map((ok,i)=><span key={i} style={{fontSize:20}}>{ok?"✅":"❌"}</span>)}
        </div>
        <div style={{display:"flex",gap:8,justifyContent:"center"}}>
          <button onClick={restart} style={{padding:"10px 20px",borderRadius:10,border:"none",background:T.surface,color:T.text,cursor:"pointer",fontSize:14}}>Снова</button>
          <button onClick={onComplete} style={{padding:"10px 20px",borderRadius:10,border:"none",background:opening.color,color:"#fff",cursor:"pointer",fontSize:14,fontWeight:700}}>Завершить ✓</button>
        </div>
      </div>
    );
  }

  return(
    <div>
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}>
        <span style={{fontSize:12,color:T.subtext}}>Вопрос {qi+1}/{quiz.length}</span>
        <span style={{fontSize:12,color:T.subtext}}>{score} правильных</span>
      </div>
      <div style={{height:4,background:T.surface,borderRadius:2,marginBottom:16}}>
        <div style={{height:"100%",width:`${(qi/quiz.length)*100}%`,background:opening.color,borderRadius:2,transition:"width .4s"}}/>
      </div>
      <div style={{background:T.surface,border:`1px solid ${T.border}`,borderRadius:12,padding:14,marginBottom:12,fontSize:15,lineHeight:1.55,fontWeight:600}}>{q.q}</div>
      <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:12}}>
        {q.opts.map((opt,i)=>{
          let bg=T.surface,border=`1px solid ${T.border}`,col=T.text;
          if(chosen!==null){if(i===q.ans){bg="rgba(39,174,96,.2)";border="1px solid #27AE60";col="#81C784";}else if(i===chosen){bg="rgba(231,76,60,.2)";border="1px solid #E74C3C";col="#EF9A9A";}}
          return(<button key={i} onClick={()=>choose(i)} disabled={chosen!==null} style={{padding:"11px 14px",borderRadius:11,border,background:bg,color:col,textAlign:"left",fontSize:13,lineHeight:1.4,cursor:chosen!==null?"default":"pointer",transition:"all .2s"}}>
            <span style={{color:T.subtext,marginRight:8,fontWeight:700}}>{"ABCD"[i]}.</span>{opt}
          </button>);
        })}
      </div>
      {chosen!==null&&(
        <div style={{background:chosen===q.ans?"rgba(39,174,96,.12)":"rgba(231,76,60,.12)",border:`1px solid ${chosen===q.ans?"rgba(39,174,96,.4)":"rgba(231,76,60,.4)"}`,borderRadius:12,padding:12,marginBottom:12,fontSize:13,lineHeight:1.5,color:T.text}}>
          <span style={{fontWeight:700,marginRight:4}}>{chosen===q.ans?"✅ Верно!":"❌ Неверно."}</span>{q.exp}
        </div>
      )}
      {chosen!==null&&<button onClick={next} style={{width:"100%",padding:"12px",borderRadius:12,border:"none",background:opening.color,color:"#fff",cursor:"pointer",fontSize:14,fontWeight:700}}>{qi<quiz.length-1?"Следующий →":"Результат →"}</button>}
    </div>
  );
}

// ═══════════════ OPENING DETAIL ═══════════════
function OpeningDetail({opening,progress,onProgress,onBack,theme}){
  const [varId,setVarId]=useState(opening.variations[0].id);
  const [tab,setTab]=useState("learn");
  const variation=opening.variations.find(v=>v.id===varId);
  const positions=useMemo(()=>buildPositions(variation.moves),[varId]);
  const vp=getVP(progress,opening.id,varId);
  const T=theme;

  const markLearn=()=>onProgress(setVP(progress,opening.id,varId,{l:true}));
  const markPractice=()=>onProgress(setVP(progress,opening.id,varId,{p:true}));
  const markQuiz=(score)=>onProgress(setVP(progress,opening.id,varId,{q:score}));

  const starsForVar=(vid)=>{const p=getVP(progress,opening.id,vid);return(p.l?1:0)+(p.p?1:0)+(p.q!==null?1:0);};

  return(
    <div style={{maxWidth:540,margin:"0 auto",padding:"12px 12px 60px"}}>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
        <button onClick={onBack} style={{padding:"7px 14px",borderRadius:8,border:`1px solid ${T.border}`,background:T.surface,color:T.text,cursor:"pointer",fontSize:13}}>← Назад</button>
        <div>
          <div style={{fontFamily:"Georgia,serif",fontSize:18,fontWeight:700}}>{opening.emoji} {opening.name}</div>
          <div style={{fontSize:11,color:T.subtext}}>{opening.tagline}</div>
        </div>
      </div>
      <div style={{background:T.surface,borderRadius:12,padding:"11px 14px",marginBottom:12,fontSize:13,color:T.text,lineHeight:1.6,borderLeft:`3px solid ${opening.color}`}}>
        {opening.desc}
        <span style={{marginLeft:8,padding:"2px 8px",borderRadius:8,fontSize:11,fontWeight:700,background:opening.playAs==="white"?"rgba(255,255,255,.15)":"rgba(0,0,0,.35)",color:"#fff"}}>{opening.playAs==="white"?"♔ Белые":"♚ Чёрные"}</span>
      </div>

      {/* Variation selector */}
      <div style={{marginBottom:14}}>
        <div style={{fontSize:11,color:T.subtext,marginBottom:8,textTransform:"uppercase",letterSpacing:".05em"}}>Варианты дебюта:</div>
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {opening.variations.map(v=>{
            const stars=starsForVar(v.id);
            const active=v.id===varId;
            return(
              <button key={v.id} onClick={()=>{setVarId(v.id);setTab("learn");}} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 14px",borderRadius:10,border:active?`2px solid ${opening.color}`:`1px solid ${T.border}`,background:active?`${opening.color}18`:T.surface,color:T.text,cursor:"pointer",textAlign:"left",transition:"all .15s"}}>
                <div>
                  <div style={{fontWeight:active?700:500,fontSize:14}}>{v.name}</div>
                  <div style={{fontSize:11,color:T.subtext,marginTop:2}}>{v.eco} · {v.moves.length} ходов</div>
                </div>
                <div style={{display:"flex",gap:3,fontSize:14}}>
                  {[0,1,2].map(i=><span key={i} style={{opacity:i<stars?1:.25}}>⭐</span>)}
                </div>
              </button>
            );
          })}
        </div>
      </div>

      {/* Tab selector */}
      <div style={{display:"flex",gap:5,marginBottom:14,background:T.surface,borderRadius:12,padding:5}}>
        {[["learn","📚 Изучение"],["practice","♟ Практика"],["quiz","📝 Тест"]].map(([id,lbl])=>(
          <button key={id} onClick={()=>setTab(id)} style={{flex:1,padding:"9px 4px",borderRadius:9,border:"none",background:tab===id?opening.color:"transparent",color:tab===id?"#fff":T.subtext,cursor:"pointer",fontSize:12,fontWeight:tab===id?700:500,transition:"all .2s"}}>{lbl}</button>
        ))}
      </div>

      {tab==="learn"&&<LearnMode key={varId+"l"} opening={opening} variation={variation} positions={positions} onComplete={markLearn} theme={T}/>}
      {tab==="practice"&&<PracticeMode key={varId+"p"} opening={opening} variation={variation} positions={positions} onComplete={markPractice} theme={T}/>}
      {tab==="quiz"&&<QuizMode key={varId+"q"} opening={opening} variation={variation} onComplete={(s)=>markQuiz(s)} theme={T}/>}
    </div>
  );
}

// ═══════════════ HOME ═══════════════
function Home({progress,onSelect,onStats,theme}){
  const T=theme;
  const totalVars=OPENINGS.reduce((s,o)=>s+o.variations.length,0);
  const completedVars=OPENINGS.reduce((s,o)=>s+o.variations.filter(v=>{const p=getVP(progress,o.id,v.id);return p.l&&p.p&&p.q!==null;}).length,0);

  return(
    <div style={{maxWidth:540,margin:"0 auto",padding:"20px 12px 60px"}}>
      <div style={{textAlign:"center",marginBottom:28}}>
        <div style={{fontSize:48,marginBottom:8}}>♟</div>
        <h1 style={{fontFamily:"Georgia,serif",fontSize:26,fontWeight:700,background:`linear-gradient(135deg,#C8A84B,#F5D97A)`,WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",marginBottom:6}}>Шахматные дебюты</h1>
        <p style={{color:T.subtext,fontSize:13}}>10 дебютов · 40 вариантов · Теория, практика, тест</p>
        <div style={{marginTop:12,background:T.surface,borderRadius:10,padding:"10px 16px",display:"inline-flex",alignItems:"center",gap:12}}>
          <div style={{textAlign:"center"}}>
            <div style={{fontSize:20,fontWeight:700,color:"#F5D97A"}}>{completedVars}</div>
            <div style={{fontSize:10,color:T.subtext}}>пройдено</div>
          </div>
          <div style={{width:1,height:30,background:T.border}}/>
          <div style={{textAlign:"center"}}>
            <div style={{fontSize:20,fontWeight:700,color:T.text}}>{totalVars}</div>
            <div style={{fontSize:10,color:T.subtext}}>всего</div>
          </div>
          <div style={{width:1,height:30,background:T.border}}/>
          <div style={{flex:1,minWidth:80}}>
            <div style={{height:6,background:T.cardBg,borderRadius:3}}>
              <div style={{height:"100%",width:`${(completedVars/totalVars)*100}%`,background:"#F5D97A",borderRadius:3,transition:"width .5s"}}/>
            </div>
            <div style={{fontSize:10,color:T.subtext,marginTop:3}}>{Math.round((completedVars/totalVars)*100)}%</div>
          </div>
        </div>
      </div>

      <div style={{display:"flex",flexDirection:"column",gap:10}}>
        {OPENINGS.map(op=>{
          const vars=op.variations;
          const done=vars.filter(v=>{const p=getVP(progress,op.id,v.id);return p.l&&p.p&&p.q!==null;}).length;
          const pct=done/vars.length;
          return(
            <div key={op.id} onClick={()=>onSelect(op)} style={{background:T.surface,borderRadius:16,padding:"14px 16px",cursor:"pointer",border:`1px solid ${T.border}`,position:"relative",overflow:"hidden",transition:"transform .15s"}}
              onMouseEnter={e=>{e.currentTarget.style.transform="translateY(-2px)";e.currentTarget.style.border=`1px solid ${op.color}`;}}
              onMouseLeave={e=>{e.currentTarget.style.transform="";e.currentTarget.style.border=`1px solid ${T.border}`;}}>
              <div style={{position:"absolute",top:0,right:0,width:100,height:"100%",background:`linear-gradient(135deg,transparent,${op.color}20)`,borderRadius:"0 15px 15px 0"}}/>
              <div style={{display:"flex",alignItems:"center",gap:10,position:"relative"}}>
                <div style={{fontSize:30,width:40,textAlign:"center"}}>{op.emoji}</div>
                <div style={{flex:1}}>
                  <div style={{fontFamily:"Georgia,serif",fontSize:15,fontWeight:700,marginBottom:2}}>{op.name}</div>
                  <div style={{color:T.subtext,fontSize:11,marginBottom:6}}>{op.tagline}</div>
                  <div style={{height:4,background:T.cardBg,borderRadius:2}}>
                    <div style={{height:"100%",width:`${pct*100}%`,background:op.color,borderRadius:2,transition:"width .5s"}}/>
                  </div>
                  <div style={{fontSize:10,color:T.subtext,marginTop:3}}>{done}/{vars.length} вариантов</div>
                </div>
                <div style={{padding:"3px 8px",borderRadius:8,fontSize:11,fontWeight:700,background:op.playAs==="white"?"rgba(255,255,255,.15)":"rgba(0,0,0,.4)",color:op.playAs==="white"?"#fff":"#ccc",border:`1px solid ${T.border}`,whiteSpace:"nowrap"}}>
                  {op.playAs==="white"?"♔ Белые":"♚ Чёрные"}
                </div>
              </div>
            </div>
          );
        })}
      </div>
      <div style={{textAlign:"center",marginTop:16,color:T.subtext,fontSize:11}}>Нажмите на дебют для начала обучения</div>
    </div>
  );
}

// ═══════════════ APP ═══════════════
const CSS=`
@import url('https://fonts.googleapis.com/css2?family=Georgia&display=swap');
*{box-sizing:border-box;margin:0;padding:0;}
body{background:#0f0e13;}
button{font-family:inherit;}
::-webkit-scrollbar{width:4px;}::-webkit-scrollbar-track{background:#12121e;}::-webkit-scrollbar-thumb{background:#333;border-radius:2px;}
@keyframes fadeIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
.fade{animation:fadeIn .3s ease forwards;}
`;

export default function App(){
  const [themeKey,setThemeKey]=useState("dark");
  const [opening,setOpening]=useState(null);
  const [progress,setProgress]=useState(loadProg);
  const theme=THEMES[themeKey];

  return(
    <div style={{minHeight:"100vh",background:theme.bg,color:theme.text,fontFamily:"-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif"}}>
      <style>{CSS}</style>
      {/* Theme toggle */}
      <div style={{position:"fixed",top:12,right:12,zIndex:100}}>
        <button onClick={()=>setThemeKey(k=>k==="dark"?"light":"dark")} style={{padding:"6px 12px",borderRadius:20,border:`1px solid ${theme.border}`,background:theme.surface,color:theme.text,cursor:"pointer",fontSize:13}}>
          {themeKey==="dark"?"☀️":"🌙"}
        </button>
      </div>
      {opening
        ?<OpeningDetail opening={opening} progress={progress} onProgress={setProgress} onBack={()=>setOpening(null)} theme={theme}/>
        :<Home progress={progress} onSelect={setOpening} theme={theme}/>
      }
    </div>
  );
}
